import java.util.*;

abstract class Shape {
    abstract double getArea();
    abstract double getPerimeter();
}

class Rectangle extends Shape {
    double length, width;

    Rectangle(double length, double width) {
        this.length = length;
        this.width = width;
    }

    double getArea() {
        return length * width;
    }

    double getPerimeter() {
        return 2 * (length + width);
    }
}

class Circle extends Shape {
    double radius;

    Circle(double radius) {
        this.radius = radius;
    }

    double getArea() {
        return Math.PI * radius * radius;
    }

    double getPerimeter() {
        return 2 * Math.PI * radius;
    }
}

class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = Integer.parseInt(sc.nextLine());

        for (int i = 0; i < n; i++) {
            String[] input = sc.nextLine().split(" ");
            String shapeType = input[0];

            Shape shape = null;
            if (shapeType.equals("Rectangle")) {
                double l = Double.parseDouble(input[1]);
                double w = Double.parseDouble(input[2]);
                shape = new Rectangle(l, w);
            } else if (shapeType.equals("Circle")) {
                double r = Double.parseDouble(input[1]);
                shape = new Circle(r);
            }

            if (shape != null) {
                System.out.printf("Area: %.2f, Perimeter: %.2f%n",
                        shape.getArea(), shape.getPerimeter());
            }
        }
    }
}

